function CountdownTimer() {
  const [target, setTarget] = React.useState('REPLACE_WITH_DATE');
  const [now, setNow] = React.useState(new Date());

  React.useEffect(()=>{
    const id = setInterval(()=>setNow(new Date()),1000);
    return ()=>clearInterval(id);
  },[]);

  const t = new Date(target);
  const diff = t - now;
  const days = Math.floor(diff/(1000*60*60*24));
  const hours = Math.floor((diff%(1000*60*60*24))/(1000*60*60));
  const mins = Math.floor((diff%(1000*60*60))/(1000*60));
  const secs = Math.floor((diff%(1000*60))/1000);

  const pad = (n)=>String(n).padStart(2,'0');

  return (
    <div style={{padding:20,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center'}}>
      <div style={{fontSize:18,fontWeight:700,marginBottom:12}}>Countdown</div>
      <input type="datetime-local" value={target} onChange={e=>setTarget(e.target.value)}
        style={{padding:'8px 12px',borderRadius:8,border:'1px solid #ccc',fontSize:14,marginBottom:20}}/>
      {diff > 0 ? (
        <div style={{display:'flex',gap:12}}>
          {[{l:'Days',v:days},{l:'Hrs',v:hours},{l:'Min',v:mins},{l:'Sec',v:secs}].map(u=> (
            <div key={u.l} style={{textAlign:'center'}}>
              <div style={{width:60,height:60,background:'#007AFF',color:'#fff',borderRadius:12,display:'flex',alignItems:'center',justifyContent:'center',fontSize:24,fontWeight:700,marginBottom:6}}>
                {pad(u.v)}
              </div>
              <div style={{fontSize:11,color:'#888',textTransform:'uppercase'}}>{u.l}</div>
            </div>
          ))}
        </div>
      ) : (
        <div style={{fontSize:24,fontWeight:700,color:'#FF3B30'}}>Time's up!</div>
      )}
    </div>
  );
}
render(<CountdownTimer/>);
